2119	\begin{theorem}[The strata ideal is quasi-coherent]
2120	  \label{thm:map_strata_ideal_basic_open}
2121	  \lean{AlgebraicGeometry.Scheme.Modules.map_strataIdeal_basicOpen}
2122	  \leanok
2123	  \uses{def:strata_ideal, lem:charts_cover_finite, lem:mem_strata_ideal_of_charts,
2124	    lem:entry_ideal_basic_open, thm:strata_ideal_eq_entry_ideal}
2125	  \source{nitsure-hilbert-quot}
2126	  Suppose \(\mathcal G\) admits \(e\)-presentation charts.  For an affine open
2127	  \(U\) and \(f \in \Gamma(X, U)\), restriction along
2128	  \(\Gamma(X, U) \to \Gamma(X, D(f))\) carries the strata ideal to the strata
2129	  ideal: the image of \(I_e(U)\) generates \(I_e(D(f))\).  Consequently the
2130	  assignment \(U \mapsto I_e(U)\) is quasi-coherent.
2131	\end{theorem}
2132	
2133	\begin{proof}
2134	  \leanok
2135	  For \(\subseteq\): any presentation chart \(W \subseteq D(f)\) is also a
2136	  chart in \(U\), so a section of \(I_e(U)\) restricts into \(I(\psi_W)\);
2137	  hence its restriction to \(D(f)\) lies in \(I_e(D(f))\).
2138	
2139	  For \(\supseteq\): let \(r' \in I_e(D(f))\) and write
2140	  \(r' = y / f^{n}\) with \(y \in \Gamma(X, U)\).  By
2141	  \cref{lem:charts_cover_finite} choose finitely many presentation charts
2142	  \(V_1, \dots, V_N\) covering \(U\), with presentations \(P_i\).  On each
2143	  \(V_i\), the basic open \(D(f|_{V_i}) \subseteq D(f)\) is a chart, and the
2144	  strata condition on \(r'\) there says \(y / f^{n}\) restricts into
2145	  \(I(\psi_{P_i}|_{D(f|_{V_i})})\), the image ideal
2146	  (\cref{lem:entry_ideal_basic_open}); clearing the denominator yields an
2147	  exponent \(m_i\) with \(f^{m_i} y|_{V_i} \in I(\psi_{P_i})\).  Setting
2148	  \(m = \max_i m_i\), multiplying up gives
2149	  \(f^{m} y|_{V_i} \in I(\psi_{P_i})\) for all \(i\), so
2150	  \(f^{m} y \in I_e(U)\) by \cref{lem:mem_strata_ideal_of_charts}.  Therefore
2151	  \(r' = (f^{m} y) / f^{m + n}\) lies in the image of \(I_e(U)\) under
2152	  restriction.  (\cref{thm:strata_ideal_eq_entry_ideal} identifies the strata
2153	  ideal with the entry ideal on each chart, licensing the denominator
2154	  clearing.)
2155	\end{proof}
